import os
from flask import Flask, request, jsonify
from kafka import KafkaProducer

KAFKA_BOOTSTRAP_SERVERS = os.getenv("KAFKA_BOOTSTRAP_SERVERS", "localhost:9092")
KAFKA_CLIENT_ID = os.getenv("KAFKA_CLIENT_ID", "flexible-event-publisher")
KAFKA_ACKS = os.getenv("KAFKA_ACKS", "1")
KAFKA_LINGER_MS = int(os.getenv("KAFKA_LINGER_MS", "10"))
KAFKA_BATCH_SIZE = int(os.getenv("KAFKA_BATCH_SIZE", "16384"))
KAFKA_RETRIES = int(os.getenv("KAFKA_RETRIES", "3"))
KAFKA_REQUEST_TIMEOUT_MS = int(os.getenv("KAFKA_REQUEST_TIMEOUT_MS", "30000"))

app = Flask(__name__)

producer = KafkaProducer(
    bootstrap_servers=[s.strip() for s in KAFKA_BOOTSTRAP_SERVERS.split(",") if s.strip()],
    client_id=KAFKA_CLIENT_ID,
    acks=KAFKA_ACKS,
    linger_ms=KAFKA_LINGER_MS,
    batch_size=KAFKA_BATCH_SIZE,
    retries=KAFKA_RETRIES,
    request_timeout_ms=KAFKA_REQUEST_TIMEOUT_MS,
    value_serializer=lambda v: v if isinstance(v, (bytes, bytearray)) else str(v).encode("utf-8"),
)

@app.route("/publish", methods=["GET", "POST"])
def publish():
    topic = request.args.get("topic") or (request.json.get("topic") if request.is_json else None) or request.form.get("topic")
    if not topic:
        return jsonify({"error": "Missing 'topic'"}), 400

    msg = request.args.get("message")
    if msg is None:
        if request.is_json:
            msg = request.json.get("message")
        if msg is None:
            msg = request.form.get("message")
    if msg is None:
        msg = request.get_data(as_text=True)

    future = producer.send(topic, msg)
    record_md = future.get(timeout=10)

    return jsonify({
        "topic": record_md.topic,
        "partition": record_md.partition,
        "offset": record_md.offset,
        "timestamp": getattr(record_md, "timestamp", None),
    })

@app.route("/health", methods=["GET"])
def health():
    return "ok", 200

def main():
    host = os.getenv("HOST", "0.0.0.0")
    port = int(os.getenv("PORT", "8080"))
    app.run(host=host, port=port, threaded=True)

if __name__ == "__main__":
    main()